SELECT id, order_no, user_id, total_amount, pay_amount, status, address_snapshot,
       pay_time, ship_time, complete_time, create_time, update_time
FROM t_order
WHERE user_id = #{userId}
ORDER BY create_time DESC
LIMIT #{offset}, #{size}

