mapper.update:
UPDATE t_order
SET status     = 'PAID',
    pay_amount = #{payAmount},
    pay_time   = #{payTime}
WHERE order_no = #{orderNo}
  AND status = 'PENDING_PAY'

UPDATE t_order
SET status    = 'SHIPPED',
    ship_time = #{shipTime}
WHERE id = #{id}
  AND status = 'PAID'

